import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,d as e}from"./app-b2b64365.js";const i={},l=e(`<h1 id="版本管理" tabindex="-1"><a class="header-anchor" href="#版本管理" aria-hidden="true">#</a> 版本管理</h1><h2 id="介绍" tabindex="-1"><a class="header-anchor" href="#介绍" aria-hidden="true">#</a> 介绍</h2><p>Go Version Manager（GVM）是一个用于管理 Go 语言版本的工具。它允许您同时在同一系统中安装多个 Go 版本，并通过简单的命令来切换使用不同版本的 Go。</p><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><h3 id="安装依赖" tabindex="-1"><a class="header-anchor" href="#安装依赖" aria-hidden="true">#</a> 安装依赖</h3><blockquote><p>Debian/Ubuntu</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt-get</span> <span class="token function">install</span> <span class="token function">curl</span> <span class="token function">git</span> mercurial <span class="token function">make</span> binutils bison gcc build-essential
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p>Redhat/Centos</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> yum <span class="token function">install</span> <span class="token function">curl</span>
<span class="token function">sudo</span> yum <span class="token function">install</span> <span class="token function">git</span>
<span class="token function">sudo</span> yum <span class="token function">install</span> <span class="token function">make</span>
<span class="token function">sudo</span> yum <span class="token function">install</span> bison
<span class="token function">sudo</span> yum <span class="token function">install</span> gcc
<span class="token function">sudo</span> yum <span class="token function">install</span> glibc-devel
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>Mac</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>xcode-select <span class="token parameter variable">--install</span>
brew update
brew <span class="token function">install</span> mercurial
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="安装gvm" tabindex="-1"><a class="header-anchor" href="#安装gvm" aria-hidden="true">#</a> 安装gvm</h3><blockquote><p>选择当前环境使用的shell(zsh、bash)，执行shell脚本</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">zsh</span> <span class="token operator">&lt;</span> <span class="token operator">&lt;</span><span class="token punctuation">(</span><span class="token function">curl</span> <span class="token parameter variable">-s</span> <span class="token parameter variable">-S</span> <span class="token parameter variable">-L</span> https://raw.githubusercontent.com/moovweb/gvm/master/binscripts/gvm-installer<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="添加配置" tabindex="-1"><a class="header-anchor" href="#添加配置" aria-hidden="true">#</a> 添加配置</h3><blockquote><p>添加环境变量到<code>~/.zshrc</code>​或 <code>~/.bashrc</code>​</p></blockquote><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>export GO_BINARY_BASE_URL=https://golang.google.cn/dl/
[[ -s &quot;$HOME/.gvm/scripts/gvm&quot; ]] &amp;&amp; source &quot;$HOME/.gvm/scripts/gvm&quot;
export GOROOT_BOOTSTRAP=$GOROOT
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>配置解释</p></blockquote><p>命令中的 <code>GO_BINARY_BASE_URL</code> 变量，定义了我们将从何处下载 Golang 的二进制文件或源码压缩包进行安装。当然，你也可以将其替换为下面的任意一个。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code># 官方地址
https://go.dev/dl/
# 官方国内镜像地址
https://golang.google.cn/dl/
# 阿里云镜像
https://mirrors.aliyun.com/golang/
# 中科大镜像
http://mirrors.ustc.edu.cn/golang/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[[ -s &quot;$HOME/.gvm/scripts/gvm&quot; ]] &amp;&amp; source &quot;$HOME/.gvm/scripts/gvm&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这条命令，是根据软件的实际安装情况来选择性加载 <code>gvm</code>​。相比较前文中安装完毕 <code>gvm</code>​ 日志输出内容推荐我们直接使用 <code>source</code>​ 命令加载 <code>gvm</code>​，这样可以更安全的执行命令，当且仅当 <code>~/.gvm</code>​ 存在的时候才会加载程序，将 <code>gvm</code>​ 注册到你当前的 <code>SHELL</code>​ 环境中。</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>export GOROOT_BOOTSTRAP=$GOROOT
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>最后一条命令，则是为了确保 Golang 使用源码编译安装时，不会出错（golang 1.14后需要 ）</p><h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h2><blockquote><p>可以使用<code>gvm help</code>​​查看所有可用的命令</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gvm version  <span class="token comment">#查看安装的gvm版本</span>
gvm listall <span class="token comment"># 获取所有服务器上可安装的golang版本集合</span>
gvm list <span class="token comment"># 查看本地已经安装的golang版本集合</span>
gvm <span class="token function">install</span> <span class="token number">1.16</span>  <span class="token comment"># 编译源码的方式安装golang1.16到本地</span>
gvm <span class="token function">install</span> go1.17 <span class="token parameter variable">-B</span>  <span class="token comment"># 二进制文件的方式安装golang1.17到本地</span>
gvm use go1.16 <span class="token comment"># 切换golang版本到1.16</span>
gvm use go1.17 <span class="token parameter variable">--default</span>  <span class="token comment"># go1.17设为默认版本</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>Go 1.5+ 从工具链中删除了 C 编译器，并用Go 编写的编译器替换了它们。为了编译 Go 1.5+，请确保首先安装 Go 1.4。</p></blockquote><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gvm <span class="token function">install</span> go1.4 <span class="token parameter variable">-B</span>
gvm use go1.4
gvm <span class="token function">install</span> go1.5
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>‍</p>`,30),c=[l];function o(t,d){return s(),a("div",null,c)}const p=n(i,[["render",o],["__file","版本管理.html.vue"]]);export{p as default};
